        """处理 /start 命令"""
        user_id = update.effective_user.id
        username = update.effective_user.username or ""
        first_name = update.effective_user.first_name or ""
        
        # 保存用户数据到数据库
        self.db.save_user(user_id, username, first_name, "")
        
        self.show_main_menu(update, user_id)
    
